<?php require_once 'functions.php'; layout_header('Контакты');
$sent=false; if($_SERVER['REQUEST_METHOD']==='POST'){ $msg=['name'=>trim($_POST['name']??''),'email'=>trim($_POST['email']??''),'message'=>trim($_POST['message']??''),'date'=>date('c')]; $file='storage/messages.json'; $list=file_exists($file)?json_decode(file_get_contents($file),true):[]; if(!is_array($list)) $list=[]; $list[]=$msg; file_put_contents($file,json_encode($list,JSON_UNESCAPED_UNICODE|JSON_PRETTY_PRINT)); $sent=true; }
?>
